// Detecta o app de destino pelo número de telefone
// Lê coluna `app` em whatsapp_contacts: 'irrigaagro' | 'agromanage' | 'ambos'

const payload = $input.first().json.body;
const data = payload.data || payload;
const remoteJid = data.key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '');
const fromMe = data.key?.fromMe || false;

if (fromMe || !phone) {
  return [{ json: { skip: true, phone } }];
}

// Filtra grupos
if (remoteJid.endsWith('@g.us')) {
  return [{ json: { skip: true, phone, reason: 'group' } }];
}

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;

const response = await fetch(
  `${supabaseUrl}/rest/v1/whatsapp_contacts?phone=eq.${phone}&is_active=eq.true&select=id,company_id,app&limit=1`,
  {
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`,
    }
  }
);

const contacts = await response.json();
const contact = Array.isArray(contacts) && contacts.length > 0 ? contacts[0] : null;

if (!contact) {
  return [{ json: { skip: true, phone, reason: 'unknown_number' } }];
}

const app = contact.app || 'irrigaagro';

// Para contatos 'ambos': detecta prefixo na mensagem
let routeTo = app;
if (app === 'ambos') {
  const text = (data.message?.conversation || data.message?.extendedTextMessage?.text || '').toUpperCase().trim();
  if (text.startsWith('AGRO ') || text === 'AGRO') {
    routeTo = 'agromanage';
  } else {
    routeTo = 'irrigaagro';
  }
}

return [{ json: { phone, app, routeTo, skip: false, company_id: contact.company_id, payload } }];

// Normaliza o payload bruto da Evolution API para o formato IncomingMessage do AgroManager

const routerData = $input.first().json;
const payload = routerData.payload;
const data = payload.data || payload;
const phone = routerData.phone;
const companyId = routerData.company_id; // UUID da empresa no AgroManager

// Detectar tipo da mensagem
const msg = data.message || {};
let messageType = 'text';
let content = '';
let mediaUrl = null;
let mediaMimeType = null;

if (msg.conversation) {
  messageType = 'text';
  content = msg.conversation;
} else if (msg.extendedTextMessage?.text) {
  messageType = 'text';
  content = msg.extendedTextMessage.text;
} else if (msg.audioMessage) {
  messageType = 'audio';
  content = '[áudio]';
  mediaMimeType = msg.audioMessage.mimetype || 'audio/ogg';
  // URL para download via Evolution API
  const messageId = data.key?.id || '';
  const instance = $env.EVOLUTION_INSTANCE || 'N8N-L24h';
  mediaUrl = `${$env.EVOLUTION_API_URL}/chat/getBase64FromMediaMessage/${instance}`;
} else if (msg.imageMessage) {
  messageType = 'image';
  content = msg.imageMessage.caption || '[imagem]';
  mediaMimeType = msg.imageMessage.mimetype || 'image/jpeg';
  const instance = $env.EVOLUTION_INSTANCE || 'N8N-L24h';
  mediaUrl = `${$env.EVOLUTION_API_URL}/chat/getBase64FromMediaMessage/${instance}`;
} else if (msg.documentMessage) {
  messageType = 'document';
  content = msg.documentMessage.title || msg.documentMessage.fileName || '[documento]';
  mediaMimeType = msg.documentMessage.mimetype || 'application/pdf';
} else {
  // Tipo não suportado (sticker, reaction, etc.) — pula
  return [{ json: { skip: true, reason: 'unsupported_type' } }];
}

// Nome do contato (pushName)
const userName = data.pushName || null;

// Montar IncomingMessage
const incomingMessage = {
  channel: 'evolution_api',
  channel_message_id: data.key?.id || null,
  phone_number: phone,
  user_name: userName,
  empresa_id: companyId,
  message_type: messageType,
  content: content,
  media_url: mediaUrl,
  media_mime_type: mediaMimeType,
  // Passar payload original para uso posterior (envio de resposta)
  _evolution_phone: phone,
  _evolution_instance: $env.EVOLUTION_INSTANCE || 'N8N-L24h',
  _evolution_api_url: $env.EVOLUTION_API_URL,
};

return [{ json: incomingMessage }];

// Envia a resposta da Edge Function de volta ao usuário via Evolution API

const edgeResponse = $input.first().json;
const replyMessage = edgeResponse.reply_message;

if (!replyMessage) {
  return [{ json: { sent: false, reason: 'no_reply_message' } }];
}

// Recuperar dados do nó de normalização
const normData = $('Normalizar p/ AgroManager').first().json;
const phone = normData._evolution_phone;
const evolutionApiUrl = normData._evolution_api_url || $env.EVOLUTION_API_URL;
const instance = normData._evolution_instance || $env.EVOLUTION_INSTANCE || 'N8N-L24h';

if (!phone || !evolutionApiUrl) {
  return [{ json: { sent: false, reason: 'missing_phone_or_url' } }];
}

const response = await fetch(
  `${evolutionApiUrl}/message/sendText/${instance}`,
  {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'apikey': $env.EVOLUTION_API_KEY,
    },
    body: JSON.stringify({
      number: phone,
      text: replyMessage,
    })
  }
);

const result = await response.json().catch(() => ({}));

return [{ json: { sent: true, phone, status: response.status, result } }];
